pragma solidity ^0.8.26;

contract AMM {
    uint256 public reserveA;
    uint256 public reserveB;
    uint256 public constant FEE_BP = 30;

    error ZeroAmount();
    error ZeroReserve();
    error InsufficientOutput();

    constructor(uint256 _reserveA, uint256 _reserveB) {
        if (_reserveA == 0 || _reserveB == 0) revert ZeroReserve();
        reserveA = _reserveA;
        reserveB = _reserveB;
    }

    function getAmountOut(
        uint256 amountIn,
        uint256 reserveIn,
        uint256 reserveOut
    ) public pure returns (uint256) {
        if (amountIn == 0 || reserveIn == 0 || reserveOut == 0) return 0;
        uint256 amountInWithFee = [[SLOT with_fee]];
        uint256 numerator = [[SLOT numerator]];
        uint256 denominator = [[SLOT denominator]];
        return [[SLOT result_calc]];
    }

    function swapAForB(uint256 amountIn) external returns (uint256 amountOut) {
        if (amountIn == 0) revert ZeroAmount();
        amountOut = getAmountOut(amountIn, reserveA, reserveB);
        if (amountOut == 0) revert InsufficientOutput();
        reserveA += amountIn;
        reserveB -= amountOut;
        return amountOut;
    }

    function swapBForA(uint256 amountIn) external returns (uint256 amountOut) {
        if (amountIn == 0) revert ZeroAmount();
        amountOut = getAmountOut(amountIn, reserveB, reserveA);
        if (amountOut == 0) revert InsufficientOutput();
        reserveB += amountIn;
        reserveA -= amountOut;
        return amountOut;
    }
}
